#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 5e5+5;
int n,m,cnt,f[N],id[N],tot;
vector<int> g[N];
vector<int> SCCs[N];
stack<int> st;bool vis[N];
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void Tarjan(int u,int fa){
    f[u]=(++cnt),id[u]=f[u];
    st.push(u),vis[u]=1;bool flag=0;
    for(int v:g[u]){
        if(v==fa){
            if(flag)f[u]=min(f[u],id[v]);
            else flag=1;continue;
        }if(!id[v])Tarjan(v,u),f[u]=min(f[u],f[v]);
        else if(vis[v])f[u]=min(f[u],id[v]);
    }if(f[u]==id[u]){
        vector<int> tmp;tmp.clear();
        while(tmp.empty()||tmp.back()!=u)
            vis[st.top()]=0,tmp.pb(st.top()),st.pop();
        SCCs[++tot]=tmp;
    }return;
}
int main(){
    n=read(),m=read();
    for(int i=1;i<=m;i++){
        int x=read(),y=read();
        g[x].pb(y),g[y].pb(x);
    }for(int i=1;i<=n;i++)if(!id[i])Tarjan(i,0);
    cout<<tot<<"\n";
    for(int i=1;i<=tot;cout<<"\n"&&i++){
        cout<<SCCs[i].size()<<" ";
        for(int x:SCCs[i])cout<<x<<" ";
    }
    return 0;
}
